export function getBegrippenVoorVak(vakId: string): BegripItem[] {
  return begrippen.filter(b => b.vakken.includes(vakId))
}

export function getBegripByTerm(term: string): BegripItem | undefined {
  return begrippen.find(b => b.term.toLowerCase() === term.toLowerCase())
}
